  return (
    <div className=" container ms-5">
      <Link to={"/movies/details/12 "}>
        <div className="  ">
          <div className=" ms-4 me-4 flex flex-row md:col-span-4 lg:col-span-3 gap-4  justify-center ">
            <Card className="max-w-lg" imgSrc="https://msp.c.yimg.jp/images/v2/FUTi93tXq405grZVGgDqGyXtFeY7do_C95WjwnQfNHZWchNkW6r_u1Znuql6-HifkKMFP0Dz8dY4-Fhrl3--BRuZh2Mezn5VCmwNH7F1qanPT6WPSHctAGhAvxhMRezg7HQCHBHnKBcqfqxrBzHp29xhPrqbOFe6oFNoFeFyiO6DY-_0IZgJrIWy3x9FIJ5TBa6gNuNs_GmOQrEVcl9wBJzU-mt4UhJnxCOPaJAzUc2JnHzukWlMbg6dxOSJsgh7C3MWCp5fQDmkKbGacLRzHEVKV7gASStXQE25nZcgxhaIa-OTgcc8scf8PDbl8eX4-Z11h8BQjR8Q4QBfClXMywyg-fK2FAQecbfSbgzM0YxqccJzceNd_TYm_NyxKB_0hAymUjJ__TGeEBghJlGvbw==/depositphotos_150614902-stock-photo-unusual-cinema-concept-3d-illustration.jpg?errorImage=false" horizontal>
      <h5 className="text-2xl font-bold tracking-tight text-gray-900 dark:text-white">
        Noteworthy technology acquisitions 2021
      </h5>
      <p className="font-normal text-gray-700 dark:text-gray-400">
        Here are the biggest enterprise technology acquisitions of 2021 so far, in reverse chronological order.
      </p>
    </Card>
          </div>
        </div>
      </Link>

      <br />
    </div>
  );
};

export default Movies;
